#include <vector>
#include <algorithm>
#include <numeric>

using namespace std;

class UnionFind {
private:
    vector<int> parent;
    vector<int> rank;
    int count;

public:
    UnionFind(int n) : parent(n), rank(n, 0), count(n) {
        iota(parent.begin(), parent.end(), 0);
    }

    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    void unite(int x, int y) {
        int rootX = find(x);
        int rootY = find(y);
        if (rootX != rootY) {
            if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else if (rank[rootX] > rank[rootY]) {
                parent[rootY] = rootX;
            } else {
                parent[rootY] = rootX;
                rank[rootX]++;
            }
            count--;
        }
    }

    int getCount() const {
        return count;
    }
};

long long solve(long long n, std::vector<std::vector<long long>> edges, long long k) {
    if (k <= 1) return 0;
    if (n < k) return -1; // This case shouldn't happen as per problem constraints (1 <= k <= n)

    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    UnionFind uf(n);
    long long left = 0;
    long long right = edges.empty() ? 0 : edges.back()[2];
    long long answer = 0;

    // Check if initial count is already >= k
    if (uf.getCount() >= k) {
        return 0;
    }

    // Binary search for the minimal t
    while (left <= right) {
        long long mid = left + (right - left) / 2;
        UnionFind tempUF(n);
        for (const auto& edge : edges) {
            if (edge[2] > mid) {
                tempUF.unite(edge[0], edge[1]);
            }
        }
        if (tempUF.getCount() >= k) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return answer;
}

